export const categories = [...new Set(dictionaryData.map(e => e.category).filter(Boolean))] as string[];
export const difficulties = ['basic', 'intermediate', 'advanced'] as const;

export function searchWords(query: string): DictionaryEntry[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return dictionaryData.filter(entry =>
    entry.word.toLowerCase().includes(q) ||
    entry.hindi.includes(q) ||
    entry.definition.toLowerCase().includes(q)
  );
}

export function getWordOfDay(): DictionaryEntry {
  const today = new Date();
  const index = (today.getDate() + today.getMonth() * 31) % dictionaryData.length;
  return dictionaryData[index];
}

export function getRandomWord(): DictionaryEntry {
  return dictionaryData[Math.floor(Math.random() * dictionaryData.length)];
}

export function getWordsByDifficulty(difficulty: 'basic' | 'intermediate' | 'advanced'): DictionaryEntry[] {
  return dictionaryData.filter(e => e.difficulty === difficulty);
}

export function getWordsByCategory(category: string): DictionaryEntry[] {
  return dictionaryData.filter(e => e.category === category);
}
